                    {
                        "id": str(uuid4()),

                        "name": tool.name,
                        "args": {"query": str(uuid4()) * 100},
                    }
                ],

                id=str(uuid4()),
            )
            for _ in range(n_tools)
        ]
        + [
            AIMessage(content="answer" * 100, id=str(uuid4())),
        ]
    )

    return create_react_agent(model, [tool], checkpointer=checkpointer)


